# Simple middleware (function-based pattern)
class RequestTimingMiddleware:
    def __init__(self, get_response):
        self.get_response = get_response
        # One-time configuration

    def __call__(self, request):
        # Before view
        start = time.perf_counter()

        response = self.get_response(request)  # call next middleware/view

        # After view
        duration = time.perf_counter() - start
        response['X-Response-Time'] = f'{duration:.4f}s'
        logger.info(f'{request.method} {request.path} - {duration:.4f}s')
        return response

# Authentication middleware
class APIKeyMiddleware:
    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        if request.path.startswith('/api/'):
            api_key = request.headers.get('X-API-Key')
            if not api_key:
                from django.http import JsonResponse
                return JsonResponse({'error': 'API key required'}, status=401)
            request.api_key = api_key  # attach to request

        return self.get_response(request)

# Exception handling middleware
class ExceptionLoggingMiddleware:
    def __init__(self, get_response):
        self.get_response = get_response

    def __call__(self, request):
        return self.get_response(request)

    def process_exception(self, request, exception):
        logger.error(
            f'Unhandled exception on {request.path}: {exception}',
            exc_info=True
        )
        return None  # let Django handle it

