    class Meta:
        model = Article
        fields = ['title', 'body', 'published', 'tags']
        widgets = {
            'body': forms.Textarea(attrs={'rows': 10, 'class': 'editor'}),
            'title': forms.TextInput(attrs={'placeholder': 'Enter title'}),
        }
        labels = {
            'published': 'Publish immediately',
        }

    def clean_title(self):
        title = self.cleaned_data['title']
        if Article.objects.filter(title=title).exclude(pk=self.instance.pk).exists():
            raise ValidationError('An article with this title already exists.')
        return title

    def clean(self):
        cleaned_data = super().clean()
        title = cleaned_data.get('title', '')
        body = cleaned_data.get('body', '')
        if title and body and title.lower() in body.lower()[:50]:
            raise ValidationError('Body should not start with the title.')
        return cleaned_data

