from django.db import models
from django.db.models import QuerySet, Manager, Count

# Custom QuerySet with chainable methods
class ArticleQuerySet(QuerySet):
    def published(self):
        return self.filter(published=True)

    def draft(self):
        return self.filter(published=False)

    def recent(self, days=7):
        from django.utils import timezone
        from datetime import timedelta
        cutoff = timezone.now() - timedelta(days=days)
        return self.filter(created_at__gte=cutoff)

    def popular(self, min_views=100):
        return self.filter(views__gte=min_views)

    def by_author(self, author_name):
        return self.filter(author__name=author_name)

    def with_comment_count(self):
        return self.annotate(comment_count=Count('comments'))

# Custom Manager
class ArticleManager(Manager):
    def get_queryset(self):
        return ArticleQuerySet(self.model, using=self._db)

    # Proxy chainable methods
    def published(self):
        return self.get_queryset().published()

    def draft(self):
        return self.get_queryset().draft()

    def recent(self, days=7):
        return self.get_queryset().recent(days)

# Model
class Article(models.Model):
    title = models.CharField(max_length=200)
    body = models.TextField()
    published = models.BooleanField(default=False)
    views = models.PositiveIntegerField(default=0)
    author = models.ForeignKey('Author', on_delete=models.CASCADE)
    created_at = models.DateTimeField(auto_now_add=True)

    # Option 1: Custom manager
    objects = ArticleManager()

    # Option 2: Use QuerySet.as_manager() (simpler)
    # objects = ArticleQuerySet.as_manager()

# Usage: all methods are chainable!
Article.objects.published().recent(30).popular(50)
Article.objects.draft().by_author('Alice')
Article.objects.published().with_comment_count().order_by('-comment_count')

# Manager that changes default queryset
class PublishedManager(Manager):
    def get_queryset(self):
        return super().get_queryset().filter(published=True)

class Article(models.Model):
    # ...
    objects = ArticleManager()      # default: all articles
    published = PublishedManager()  # only published

# Article.objects.all()       -> all articles
# Article.published.all()     -> only published articles
# Article.published.recent()  -> published + recent

class ArticleQuerySet(models.QuerySet):
    def published(self):
        return self.filter(published=True)
    def recent(self):
        return self.order_by('-created_at')

class Article(models.Model):
    objects = ArticleQuerySet.as_manager()

# Usage: Article.objects.published().recent()[:5]

# BAD: N+1
for a in Article.objects.all():
    print(a.author.name)  # extra query each time

# GOOD: 1 query (JOIN)
for a in Article.objects.select_related('author'):
    print(a.author.name)  # no extra query
